def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def validate_solution(nums, target):
    result = solve(nums, target)
    if result == (-1, -1):
        return "No solution exists"
    left, right = result
    if left == right or left < 0 or right >= len(nums):
        return "Invalid indices returned"
    return "Valid solution"

# Example usage
print(validate_solution([1, 2, 3, 4, 5], 9))  # Valid solution
print(validate_solution([1, 2, 3, 4, 5], 10)) # No solution exists
